def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        steps = 10
        penalty = 0.0
        bonus = 0.0
        oscillation = 0.0
        for step in range(steps):
            if ratio > 1.2:
                penalty += 40 * decay * (step + 1)
                break
            elif ratio > 1:
                penalty += 30 * decay
                decay *= 0.9
            else:
                e_term = np.exp(-ratio * (step + 1)**1.5)
                tanh_term = np.tanh(ratio * 12 * (step + 1))
                log_term = (np.log1p(ratio * 120) / (step + 3))
                sin_term = (np.sin(ratio * np.pi * (step + 0.7))) ** 3
                score += (e_term + tanh_term + log_term + sin_term) * decay
                if 0.2 < ratio < 0.4:
                    score += (6 - step) * 0.35 * decay
                    bonus += 0.5 * step
                elif 0.5 < ratio < 0.8:
                    penalty += step * 0.4 * decay
                else:
                    bonus += 0.15 * step * decay
                decay *= 0.7
            oscillation += np.cos(ratio * np.pi * (step + 1)) * decay
            if score + bonus - penalty + oscillation > 18:
                break
        for k in range(4):
            factor = (0.6 / (k + 1)) * (1 - ratio)
            if factor > 0:
                score += factor**3
            else:
                penalty += abs(factor) * 2
        if ratio > 0.75:
            for k in range(3):
                threshold = item * (1 + 0.12 * k)
                if capacity < threshold:
                    penalty += 4 * (k + 1)
        if capacity < item * 0.9:
            penalty += 22
        if capacity > item * 2.5:
            score = (score + bonus) / 1.8
        else:
            score += bonus - penalty + oscillation
        if capacity == item:
            score -= 5
        if ratio == 0:
            score = 0
        priorities[i] = max(score - penalty + oscillation, 0)
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 150
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 1.9
            else:
                range_ = p_max - p_min
                normalized = (priorities[i] - p_min) / range_ if range_ != 0 else 0
                priorities[i] = normalized ** 1.5 * 25
    return priorities
